function escapeHtml(v) {
  return String(v || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function sqlString(v) {
  return `'${String(v || '').replace(/'/g, "''")}'`;
}

const domains = [
  { label: 'AI, Machine Learning and GenAI', terms: ['ai', 'machine learning', 'ml', 'data ai', 'analytics', 'automation', 'genai'] },
  { label: 'Software Engineering', terms: ['software', 'developer', 'engineer', 'full stack', 'backend', 'frontend'] },
  { label: 'Data Engineering', terms: ['data', 'analytics', 'data science', 'data management', 'pipeline', 'business intelligence'] },
  { label: 'Cybersecurity', terms: ['cyber', 'security', 'risk', 'technology risk', 'devsecops'] },
  { label: 'Cloud Engineering', terms: ['cloud', 'aws', 'azure', 'infrastructure', 'devops'] },
  { label: 'DevOps, Platform and Site Reliability', terms: ['devops', 'platform', 'sre', 'infrastructure', 'kubernetes'] },
  { label: 'QA and Test Automation', terms: ['qa', 'test', 'automation test', 'sdet', 'quality'] },
  { label: 'Product and Technical Product', terms: ['product', 'business analyst', 'solution engineering', 'commercial'] },
];

function resolveDomain(text) {
  const clean = String(text || '').toLowerCase();
  if (clean.includes('domain: ai') || clean.includes('ai / ml') || /\b(ai|ml|genai)\b/.test(clean)) return domains[0];
  if (clean.includes('domain: software') || clean.includes('software')) return domains[1];
  if (clean.includes('domain: data') || clean.includes('data')) return domains[2];
  if (clean.includes('domain: cyber') || clean.includes('cyber') || clean.includes('security')) return domains[3];
  if (clean.includes('domain: cloud') || clean.includes('cloud')) return domains[4];
  if (clean.includes('domain: devops') || clean.includes('devops') || clean.includes('sre')) return domains[5];
  if (clean.includes('domain: qa') || clean.includes('qa') || clean.includes('test')) return domains[6];
  if (clean.includes('domain: product') || clean.includes('product')) return domains[7];
  return null;
}

function resolveCountry(text) {
  const clean = String(text || '').toLowerCase();
  if (clean.includes('country: us') || /\b(us|usa|united states)\b/.test(clean)) return 'US';
  if (clean.includes('country: uk') || /\b(uk|gb|united kingdom|britain|england)\b/.test(clean)) return 'UK';
  if (clean.includes('country: ie') || /\b(ie|ireland|dublin)\b/.test(clean)) return 'IE';
  return '';
}

function resolveTopN(text) {
  const m = String(text || '').match(/\b(?:top\s*)?(5|10|15|20|25)\b/i);
  return m ? Number(m[1]) : 0;
}

function domainWhere(domainLabel) {
  const domain = domains.find(d => d.label === domainLabel) || domains[0];
  const cols = ['role_title', 'sector', 'location', 'notes', 'fit_reason'];
  const clauses = [];
  for (const term of domain.terms) {
    for (const col of cols) clauses.push(`${col} ILIKE ${sqlString(`%${term}%`)}`);
  }
  return `(${clauses.join(' OR ')})`;
}

function companyWhere(domainLabel) {
  const domain = domains.find(d => d.label === domainLabel) || domains[0];
  const cols = ['company_name', 'sector', 'how_to_apply', 'website_text'];
  const clauses = [];
  for (const term of domain.terms) {
    for (const col of cols) clauses.push(`${col} ILIKE ${sqlString(`%${term}%`)}`);
  }
  return `(${clauses.join(' OR ')})`;
}

function curatedSql(action, prefs) {
  const limit = Math.max(5, Math.min(25, Number(prefs.top_n || 10)));
  if (action === 'curated_roles') {
    return `
      SELECT 'curated_roles' AS result_type, company, role_title, sector, location, status,
             apply_link, COALESCE(NULLIF(apply_url, ''), apply_link) AS link,
             deadline_text, stamp_1g_ok, notes, fit_reason, priority_action, priority_score
      FROM curated_roles
      WHERE ${domainWhere(prefs.domain)}
      ORDER BY priority_score DESC, id
      LIMIT ${limit};
    `;
  }
  if (action === 'target_companies') {
    return `
      SELECT 'target_companies' AS result_type, company_name AS company, sector,
             COALESCE(NULLIF(website_url, ''), website_text) AS link,
             how_to_apply, priority_score
      FROM curated_companies
      ORDER BY priority_score DESC, company_name
      LIMIT ${limit};
    `;
  }
  if (action === 'deadlines') {
    return `
      SELECT 'deadlines' AS result_type, company, role_title, deadline_text, action, link, priority_score
      FROM curated_deadlines
      ORDER BY priority_score DESC, id
      LIMIT ${limit};
    `;
  }
  if (action === 'watchlist') {
    return `
      SELECT 'watchlist' AS result_type, company, programme, expected_opening, notes, priority_score
      FROM curated_watchlist
      ORDER BY priority_score DESC, company
      LIMIT ${limit};
    `;
  }
  if (action === 'portals') {
    return `
      SELECT 'portals' AS result_type, portal, url, best_for, results_summary, quick_tip, usefulness, priority_score
      FROM curated_portals
      ORDER BY priority_score DESC, portal
      LIMIT ${limit};
    `;
  }
  return `SELECT 'empty' AS result_type WHERE false;`;
}

const incoming = $input.first().json || {};
const message = incoming.message || {};
const chatId = message.chat?.id || 8047661784;
const text = String(message.text || '').trim();
const clean = text.toLowerCase();

const store = $getWorkflowStaticData('global');
store.telegramPrefs = store.telegramPrefs || {};
const key = String(chatId);
const prefs = store.telegramPrefs[key] || {
  domain: 'AI, Machine Learning and GenAI',
  country: 'IE',
  top_n: 10,
};

const domain = resolveDomain(text);
if (domain) prefs.domain = domain.label;

const country = resolveCountry(text);
if (country) prefs.country = country;

const topN = resolveTopN(text);
if (topN) prefs.top_n = topN;

store.telegramPrefs[key] = prefs;

let action = 'menu';
if (/(run live scan|run scan|scan|scrape|search)/.test(clean)) action = 'run_scan';
else if (/(latest live jobs|latest jobs|live jobs|latest|results)/.test(clean)) action = 'latest_results';
else if (/(curated roles|graduate roles|seed roles|best roles)/.test(clean)) action = 'curated_roles';
else if (/(target companies|companies|company targets)/.test(clean)) action = 'target_companies';
else if (/(deadline|urgent)/.test(clean)) action = 'deadlines';
else if (/(watchlist|2027)/.test(clean)) action = 'watchlist';
else if (/(portal|sources|job boards)/.test(clean)) action = 'portals';
else if (/(settings|configure|config|domain:|country:|top )/.test(clean)) action = 'settings';
else if (clean === '/start' || clean === 'start' || clean === 'hi' || clean === 'hello' || clean === 'back' || clean === 'home' || clean.includes('help')) action = 'menu';

const status = `<b>Job Radar</b>\n${escapeHtml(prefs.domain)} · ${escapeHtml(prefs.country)} · top ${prefs.top_n}`;
const menuTextByAction = {
  menu: `${status}\n\n<b>Main</b>\nUse the buttons below. This Telegram chat is the control panel.`,
  settings: `${status}\n\n<b>Settings</b>\nChoose the domain, country, and result count. Then use curated roles or run a live scan.`,
  run_scan: `${status}\n\nLive scan queued. I will send the ranked digest here when it finishes.`,
  latest_results: `${status}\n\nFetching latest live-scraped jobs from the database.`,
  curated_roles: `${status}\n\nFetching curated graduate/entry roles from the Excel seed data.`,
  target_companies: `${status}\n\nFetching target companies from the Excel seed data.`,
  deadlines: `${status}\n\nFetching urgent deadline/watch-now items from the Excel seed data.`,
  watchlist: `${status}\n\nFetching 2027 watchlist companies and programme timing.`,
  portals: `${status}\n\nFetching the best job portals/search sources from the Excel seed data.`,
};

return [{
  json: {
    chatId,
    telegram_chat_id: chatId,
    incomingText: text,
    action,
    domain: prefs.domain,
    country: prefs.country,
    top_n: prefs.top_n,
    curated_sql: curatedSql(action, prefs),
    menuText: menuTextByAction[action] || menuTextByAction.menu,
  },
}];

function escapeHtml(v) {
  return String(v || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const cmd = $('Build Command').first().json;
const jobs = $input.all().map(i => i.json).filter(j => j && j.title);

const lines = [
  '<b>Latest Stored Jobs</b>',
  `${escapeHtml(cmd.domain)} · ${escapeHtml(cmd.country)} · top ${cmd.top_n}`,
  '',
];

if (jobs.length === 0) {
  lines.push('No stored jobs yet. Press <b>Run Scan</b> first.');
} else {
  jobs.slice(0, Number(cmd.top_n || 10)).forEach((job, index) => {
    const score = Number.isFinite(Number(job.match_score)) ? Math.round(Number(job.match_score)) : 0;
    lines.push(`${index + 1}. <b>${escapeHtml(job.company || 'Unknown')}</b> - ${escapeHtml(job.title)}`);
    lines.push(`${escapeHtml(job.location || '-')} · score ${score}`);
    lines.push(escapeHtml(job.url || job.original_url || ''));
    lines.push('');
  });
}

const text = lines.join('\n');

return [{
  json: {
    chatId: cmd.chatId,
    menuText: text.length > 3900 ? `${text.slice(0, 3860)}\n\n...truncated` : text,
    action: cmd.action,
  },
}];

function escapeHtml(v) {
  return String(v || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function cleanLink(v) {
  const s = String(v || '').trim();
  if (!s) return '';
  return s.length > 180 ? `${s.slice(0, 177)}...` : s;
}

const cmd = $('Build Command').first().json;
const action = cmd.action;
const rows = $input.all().map(i => i.json).filter(r => {
  if (!r) return false;
  if (action === 'target_companies') return Boolean(r.company);
  if (action === 'curated_roles' || action === 'deadlines') return Boolean(r.role_title || r.company);
  if (action === 'watchlist') return Boolean(r.company);
  if (action === 'portals') return Boolean(r.portal);
  return Object.keys(r).length > 0;
});
const lines = [
  `<b>${{
    curated_roles: 'Curated Graduate Roles',
    target_companies: 'Target Companies',
    deadlines: 'Urgent Deadlines',
    watchlist: 'Watchlist 2027',
    portals: 'Job Portals',
  }[action] || 'Curated Results'}</b>`,
  `${escapeHtml(cmd.domain)} · ${escapeHtml(cmd.country)} · top ${cmd.top_n}`,
  '',
];

if (rows.length === 0) {
  lines.push('No matching curated rows found for this setting.');
} else if (action === 'curated_roles') {
  rows.forEach((r, i) => {
    const link = cleanLink(r.link || r.apply_link);
    lines.push(`${i + 1}. <b>${escapeHtml(r.company)}</b> - ${escapeHtml(r.role_title)}`);
    lines.push(`${escapeHtml(r.status || 'check')} · ${escapeHtml(r.location || '-')} · ${escapeHtml(r.deadline_text || 'deadline TBC')}`);
    if (r.stamp_1g_ok) lines.push(`Stamp 1G: ${escapeHtml(r.stamp_1g_ok)}`);
    if (r.priority_action) lines.push(`Action: ${escapeHtml(r.priority_action)}`);
    if (r.fit_reason) lines.push(escapeHtml(r.fit_reason));
    else if (r.notes) lines.push(escapeHtml(r.notes));
    if (link) lines.push(link);
    lines.push('');
  });
} else if (action === 'target_companies') {
  rows.forEach((r, i) => {
    const link = cleanLink(r.link);
    lines.push(`${i + 1}. <b>${escapeHtml(r.company)}</b>`);
    if (r.sector) lines.push(escapeHtml(r.sector));
    if (r.how_to_apply) lines.push(escapeHtml(r.how_to_apply));
    if (link) lines.push(link);
    lines.push('');
  });
} else if (action === 'deadlines') {
  rows.forEach((r, i) => {
    const link = cleanLink(r.link);
    lines.push(`${i + 1}. <b>${escapeHtml(r.company || 'Check portal')}</b> - ${escapeHtml(r.role_title)}`);
    lines.push(`${escapeHtml(r.deadline_text || 'deadline TBC')} · ${escapeHtml(r.action || 'verify now')}`);
    if (link) lines.push(link);
    lines.push('');
  });
} else if (action === 'watchlist') {
  rows.forEach((r, i) => {
    lines.push(`${i + 1}. <b>${escapeHtml(r.company)}</b>`);
    if (r.programme) lines.push(escapeHtml(r.programme));
    if (r.expected_opening) lines.push(`Expected: ${escapeHtml(r.expected_opening)}`);
    if (r.notes) lines.push(escapeHtml(r.notes));
    lines.push('');
  });
} else if (action === 'portals') {
  rows.forEach((r, i) => {
    lines.push(`${i + 1}. <b>${escapeHtml(r.portal)}</b> ${escapeHtml(r.usefulness || '')}`);
    if (r.best_for) lines.push(escapeHtml(r.best_for));
    if (r.results_summary) lines.push(escapeHtml(r.results_summary));
    if (r.quick_tip) lines.push(escapeHtml(r.quick_tip));
    if (r.url) lines.push(cleanLink(r.url));
    lines.push('');
  });
}

lines.push('<i>Seed data can be stale. Verify links/status before applying.</i>');

const text = lines.join('\n');

return [{
  json: {
    chatId: cmd.chatId,
    menuText: text.length > 3900 ? `${text.slice(0, 3860)}\n\n...truncated` : text,
    action,
  },
}];
